css:
.hc-bar{display:flex;flex-wrap:wrap;align-items:center;justify-content:space-between;gap:16px;height:100%;box-sizing:border-box;padding:14px 22px;background:#fff;border:1px solid rgba(0,0,0,.07);border-radius:12px;box-shadow:0 1px 3px rgba(16,24,40,.06);font-family:var(--font-stack-primary,system-ui,-apple-system,sans-serif);}
.hc-bar .hc-eyebrow{font-size:11px;letter-spacing:.14em;font-weight:700;color:var(--color-primary,#009fe4);text-transform:uppercase;}
.hc-bar .hc-title{margin:3px 0 0;font-size:22px;font-weight:800;line-height:1.1;color:var(--color-text,#222);}
.hc-bar .hc-controls{display:flex;flex-wrap:wrap;align-items:flex-end;gap:12px;}
.hc-bar .hc-field{display:flex;flex-direction:column;gap:4px;font-size:10.5px;letter-spacing:.04em;text-transform:uppercase;color:#6b7280;font-weight:700;}
.hc-bar .hc-field select{min-width:148px;padding:8px 10px;border:1px solid rgba(0,0,0,.15);border-radius:8px;background:#fff;color:var(--color-text,#222);font-size:13px;font-family:inherit;cursor:pointer;}
.hc-bar .hc-field select:focus{outline:none;border-color:var(--color-primary,#009fe4);box-shadow:0 0 0 3px rgba(0,159,228,.15);}
.hc-bar .hc-clear{align-self:flex-end;padding:9px 16px;border:1px solid var(--color-primary,#009fe4);border-radius:8px;background:transparent;color:var(--color-primary,#009fe4);font-weight:700;font-size:12px;cursor:pointer;transition:all .15s ease;}
.hc-bar .hc-clear:hover{background:var(--color-primary,#009fe4);color:#fff;}
